                "glm-5.2", "kimi-k2", "deepseek-v4-pro", "claude-opus-1m",
                "gpt-5", "hf-qwen3-coder-next",
            },
            ["balanced"] = new[]
            {
                "deepseek-v4-pro", "kimi-k2", "deepseek-v4-flash", "gpt-5",
                "hf-qwen3-coder-next", "claude-sonnet",
            },
            ["cheap"] = new[]
            {
                "deepseek-v4-flash", "deepseek-v4-pro", "hf-qwen3-coder-next",
                "gpt-5",
            },
            ["vision"] = new[]
            {
                "hf-qwen3-vl-235b", "hf-qwen3-vl-30b", "kimi-k2",
            },
            ["claude"] = new[]
            {
                "claude-opus-1m", "claude-sonnet",
            },
            ["fallback"] = new[]
            {
                "hf-qwen3-coder-next",
            },
        };

    /// <summary>
    /// Model → required env var for models that are not in any tier Chain
    /// (e.g. <c>gpt-5</c>). Merged with <see cref="ModelToKey"/> at resolution
    /// time so every selectable model has a known provider key.
    /// </summary>
    private static readonly IReadOnlyDictionary<string, string> ModelToRequiredKey =
        new Dictionary<string, string>
        {
            ["gpt-5"] = "OPENAI_API_KEY",
        };

    /// <summary>
    /// Returns the required env var for <paramref name="model"/> by checking
    /// <see cref="ModelToKey"/> first, then <see cref="ModelToRequiredKey"/>.
    /// Returns <c>null</c> when the model is <c>"fallback"</c> or unknown.
    /// </summary>
    private static string? GetRequiredKey(string model)
    {
        if (model == "fallback") return "HF_TOKEN";
        if (ModelToKey.TryGetValue(model, out var key)) return key;
        if (ModelToRequiredKey.TryGetValue(model, out var extraKey)) return extraKey;
        return null;
    }
}

