/// <summary>
/// Returns one row per tier with the resolved model, provider, and
/// key-present status for UI display. When <paramref name="overrides"/>
/// is provided, each tier honours its override if the required key is
/// present; otherwise auto-resolves as before.
/// </summary>
public static IReadOnlyList<TierConfigRow> GetTierRows(
    ISet<string> presentKeys,
    IReadOnlyDictionary<string, string>? overrides = null)
{
    var (aliases, fallbacks) = ResolveTiers(presentKeys, overrides);
    var rows = new List<TierConfigRow>();

    foreach (var tier in Chains.Keys)
    {
        if (tier == "claude" && !aliases.ContainsKey("claude"))
        {
            rows.Add(new TierConfigRow(
                Tier: "claude",
                Model: "(key missing)",
                ProviderName: "Anthropic",
                KeyPresent: false,
                FallbackChainText: null)
            {
                SelectableModels = SelectableModels.TryGetValue("claude", out var sm) ? sm : Array.Empty<string>(),
                IsEditable = true,
            });
            continue;
        }

        if (!aliases.TryGetValue(tier, out var model))
            continue;

        var requiredKey = model == "fallback" ? "HF_TOKEN"
            : ModelToKey.TryGetValue(model, out var mk) ? mk
            : ModelToRequiredKey.TryGetValue(model, out var ek) ? ek
            : "HF_TOKEN";
        var chainText = fallbacks.TryGetValue(tier, out var fb) && fb.Count > 0
            ? string.Join(", ", fb)
            : null;

        rows.Add(new TierConfigRow(
            Tier: tier,
            Model: model,
            ProviderName: ProviderNames[requiredKey],
            KeyPresent: presentKeys.Contains(requiredKey),
            FallbackChainText: chainText)
        {
            SelectableModels = SelectableModels.TryGetValue(tier, out var sm) ? sm : Array.Empty<string>(),
            IsEditable = tier != FallbackTier,
        });
    }

    return rows;
}

