using System.Text.Json;

namespace VisualRelay.Core.Configuration;

public static partial class RelayConfigLoader
{
    /// <summary>
    /// Parses the <c>tierModelOverrides</c> JSON object from
    /// <c>.relay/config.json</c>, validating each value against
    /// <see cref="BackendConfigGenerator.SelectableModels"/>. Invalid
    /// entries are silently dropped. Returns <c>null</c> for missing,
    /// empty, or fully-invalid input.
    /// </summary>
    internal static IReadOnlyDictionary<string, string>? TryParseTierModelOverrides(
        JsonElement element)
    {
        if (element.ValueKind != JsonValueKind.Object)
            return null;

        var result = new Dictionary<string, string>();
        foreach (var property in element.EnumerateObject())
        {
            var tier = property.Name;
            var model = property.Value.GetString();
            if (string.IsNullOrWhiteSpace(model))
                continue;

            // Validate: the model must be in that tier's SelectableModels.
            if (!BackendConfigGenerator.SelectableModels.TryGetValue(tier, out var allowed))
                continue;

            if (!allowed.Contains(model, StringComparer.Ordinal))
                continue;

            result[tier] = model;
        }

        return result.Count > 0 ? result : null;
    }
}

