private static string Generate(string template, string? repoRoot = null)
{
    var present = new HashSet<string>(StringComparer.Ordinal);
    foreach (var (key, _) in KeyEnvFile.Read())
        present.Add(key);
    foreach (var key in new[] { "HF_TOKEN", "DEEPSEEK_API_KEY", "MOONSHOT_API_KEY", "ANTHROPIC_API_KEY", "OPENAI_API_KEY" })
        if (Environment.GetEnvironmentVariable(key) is not null)
            present.Add(key);

    // Load tier model overrides from .relay/config.json, if present.
    IReadOnlyDictionary<string, string>? overrides = null;
    if (repoRoot is not null)
    {
        try
        {
            var configResult = RelayConfigLoader.TryLoadAsync(repoRoot).Result;
            if (configResult.Status == RelayConfigStatus.Loaded)
                overrides = configResult.Config.TierModelOverrides;
        }
        catch
        {
            // Best-effort: a missing or unreadable config falls back to auto-resolve.
        }
    }

    var (yaml, _) = BackendConfigGenerator.Generate(present, template, overrides);
    return yaml;
}

